import{f as o,D as l,o as a,c as i,a2 as r,b as A,w as e,a as h,G as n,a5 as s}from"./chunks/framework.DHYrF-q6.js";const P=JSON.parse('{"title":"AI 产品经理","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/index.md","filePath":"ai-product-manager/index.md","lastUpdated":1781090728000}'),E={name:"ai-product-manager/index.md"};function u(b,t,m,c,g,I){const d=l("Mermaid");return a(),i("div",null,[t[1]||(t[1]=r('<h1 id="ai-产品经理" tabindex="-1">AI 产品经理 <a class="header-anchor" href="#ai-产品经理" aria-label="Permalink to &quot;AI 产品经理&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>AI 产品经理（AI PM）是当下最炙手可热的职业方向之一——<strong>将 AI 技术能力转化为用户价值与商业价值的关键枢纽</strong>。本专题面向有志于转型 AI 产品经理的工程师、传统 PM、以及想建立产品思维的 AI 从业者，从<strong>角色定位 → 技术基础 → 产品设计 → 数据管理 → Prompt 工程 → 大模型与 Agent → 商业落地 → 伦理合规 → 面试实战</strong>九大模块，形成完整的 AI 产品经理能力闭环。</p><blockquote><p>2025 年 Gartner 行业报告指出，成功实现 AI 商业化的企业中，<strong>87%</strong> 配备了专业化的 AI 产品经理团队。AI PM 岗位需求同比增长 <strong>240%</strong>。</p></blockquote><div class="tip custom-block"><p class="custom-block-title">核心认知</p><p>AI 产品经理的核心使命不是&quot;把需求翻译给工程师&quot;，而是<strong>在技术可行性、用户体验与商业价值之间找到动态平衡点</strong>。这是一个需要概率思维、数据直觉和商业嗅觉的复合型角色。</p></div><div class="info custom-block"><p class="custom-block-title">适用人群</p><ul><li>正在转型 AI 产品方向的传统产品经理</li><li>想补齐产品思维的算法工程师 / 后端工程师</li><li>对 AI 产品感兴趣的零基础学习者</li><li>准备 AI PM 面试的求职者</li></ul></div><h2 id="知识图谱" tabindex="-1">知识图谱 <a class="header-anchor" href="#知识图谱" aria-label="Permalink to &quot;知识图谱&quot;">​</a></h2>',7)),(a(),A(s,null,{default:e(()=>[n(d,{id:"mermaid-46",class:"mermaid",graph:"mindmap%0A%20%20root((AI%20%E4%BA%A7%E5%93%81%E7%BB%8F%E7%90%86))%0A%20%20%20%20%E8%A7%92%E8%89%B2%E5%AE%9A%E4%BD%8D%0A%20%20%20%20%20%20AI%20PM%20vs%20%E4%BC%A0%E7%BB%9F%20PM%0A%20%20%20%20%20%20AI%20Native%20%E6%96%B9%E5%90%91%0A%20%20%20%20%20%20AI%20%E5%B9%B3%E5%8F%B0%E6%96%B9%E5%90%91%0A%20%20%20%20%20%20AI%2B%E8%A1%8C%E4%B8%9A%E6%96%B9%E5%90%91%0A%20%20%20%20%E6%8A%80%E6%9C%AF%E5%9F%BA%E7%A1%80%0A%20%20%20%20%20%20%E6%9C%BA%E5%99%A8%E5%AD%A6%E4%B9%A0%E5%9F%BA%E7%A1%80%0A%20%20%20%20%20%20%E6%B7%B1%E5%BA%A6%E5%AD%A6%E4%B9%A0%E5%85%A5%E9%97%A8%0A%20%20%20%20%20%20%E5%A4%A7%E6%A8%A1%E5%9E%8B%E5%8E%9F%E7%90%86%0A%20%20%20%20%20%20MLOps%20%E5%B7%A5%E7%A8%8B%0A%20%20%20%20%E4%BA%A7%E5%93%81%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20AI%20%E9%9C%80%E6%B1%82%E5%88%86%E6%9E%90%0A%20%20%20%20%20%20%E6%A6%82%E7%8E%87%E5%8C%96%20UX%0A%20%20%20%20%20%20%E5%A4%9A%E6%A8%A1%E6%80%81%E4%BA%A4%E4%BA%92%0A%20%20%20%20%20%20%E8%AF%84%E4%BC%B0%E6%8C%87%E6%A0%87%E4%BD%93%E7%B3%BB%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E4%B8%8E%E6%A8%A1%E5%9E%8B%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E9%87%87%E9%9B%86%E6%A0%87%E6%B3%A8%0A%20%20%20%20%20%20%E7%89%B9%E5%BE%81%E5%B7%A5%E7%A8%8B%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E9%97%AD%E7%8E%AF%0A%20%20%20%20Prompt%20%E5%B7%A5%E7%A8%8B%0A%20%20%20%20%20%20Prompt%20%E8%AE%BE%E8%AE%A1%E6%96%B9%E6%B3%95%E8%AE%BA%0A%20%20%20%20%20%20Few-shot%20%E7%AD%96%E7%95%A5%0A%20%20%20%20%20%20%E6%A8%A1%E6%9D%BF%E5%BA%93%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%E5%A4%9A%E8%BD%AE%E5%AF%B9%E8%AF%9D%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%E5%A4%A7%E6%A8%A1%E5%9E%8B%E4%B8%8E%20Agent%0A%20%20%20%20%20%20LLM%20%E8%83%BD%E5%8A%9B%E8%BE%B9%E7%95%8C%0A%20%20%20%20%20%20RAG%20%E6%9E%B6%E6%9E%84%0A%20%20%20%20%20%20Agent%20%E8%AE%BE%E8%AE%A1%E6%A8%A1%E5%BC%8F%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E9%80%89%E5%9E%8B%E4%B8%8E%E5%BE%AE%E8%B0%83%0A%20%20%20%20%E5%95%86%E4%B8%9A%E8%90%BD%E5%9C%B0%0A%20%20%20%20%20%20AI%20%E5%95%86%E4%B8%9A%E6%A8%A1%E5%BC%8F%0A%20%20%20%20%20%20%E5%AE%9A%E4%BB%B7%E7%AD%96%E7%95%A5%0A%20%20%20%20%20%20%E8%A1%8C%E4%B8%9A%E5%9C%BA%E6%99%AF%E9%80%82%E9%85%8D%0A%20%20%20%20%20%20ROI%20%E6%B5%8B%E7%AE%97%0A%20%20%20%20%E4%BC%A6%E7%90%86%E5%90%88%E8%A7%84%0A%20%20%20%20%20%20AI%20%E4%BC%A6%E7%90%86%E5%8E%9F%E5%88%99%0A%20%20%20%20%20%20%E6%B3%95%E8%A7%84%E8%A7%A3%E8%AF%BB%0A%20%20%20%20%20%20%E5%81%8F%E8%A7%81%E6%A3%80%E6%B5%8B%0A%20%20%20%20%20%20%E8%B4%9F%E8%B4%A3%E4%BB%BB%20AI%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[h(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=r('<h2 id="核心模块" tabindex="-1">核心模块 <a class="header-anchor" href="#核心模块" aria-label="Permalink to &quot;核心模块&quot;">​</a></h2><h3 id="🧭-角色定位" tabindex="-1">🧭 角色定位 <a class="header-anchor" href="#🧭-角色定位" aria-label="Permalink to &quot;🧭 角色定位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./role-overview">AI PM 角色定位与三大方向</a></td><td>与传统 PM 的本质差异、AI Native / 平台 / 行业三大方向的差异对比、能力模型</td></tr></tbody></table><h3 id="🧱-技术基础" tabindex="-1">🧱 技术基础 <a class="header-anchor" href="#🧱-技术基础" aria-label="Permalink to &quot;🧱 技术基础&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./tech-basics">AI 技术基础</a></td><td>机器学习核心概念、深度学习入门、大模型原理、MLOps、面试高频技术题</td></tr></tbody></table><h3 id="🎨-产品设计" tabindex="-1">🎨 产品设计 <a class="header-anchor" href="#🎨-产品设计" aria-label="Permalink to &quot;🎨 产品设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./product-design">AI 产品设计</a></td><td>需求分析方法、概率化 UX 设计、评估指标体系、PRD 撰写规范</td></tr></tbody></table><h3 id="📊-数据与模型管理" tabindex="-1">📊 数据与模型管理 <a class="header-anchor" href="#📊-数据与模型管理" aria-label="Permalink to &quot;📊 数据与模型管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./data-model-management">数据与模型管理</a></td><td>数据采集标注、特征工程、模型评估调优、数据闭环与漂移监控</td></tr></tbody></table><h3 id="✍️-prompt-工程" tabindex="-1">✍️ Prompt 工程 <a class="header-anchor" href="#✍️-prompt-工程" aria-label="Permalink to &quot;✍️ Prompt 工程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./prompt-engineering">Prompt 工程（AI Native 核心）</a></td><td>System Prompt 设计、Few-shot 策略、模板库 A/B 测试、多轮对话管理</td></tr></tbody></table><h3 id="🤖-大模型与-agent" tabindex="-1">🤖 大模型与 Agent <a class="header-anchor" href="#🤖-大模型与-agent" aria-label="Permalink to &quot;🤖 大模型与 Agent&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./large-model">大模型技术栈与 Agent 设计</a></td><td>LLM 能力边界评估、RAG 架构、Agent 设计模式、模型选型与微调策略</td></tr></tbody></table><h3 id="💰-商业落地" tabindex="-1">💰 商业落地 <a class="header-anchor" href="#💰-商业落地" aria-label="Permalink to &quot;💰 商业落地&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./business-commercialization">AI 商业落地与策略</a></td><td>商业模式设计、定价策略、行业场景适配、GTM 策略、ROI 计算</td></tr></tbody></table><h3 id="⚖️-伦理合规" tabindex="-1">⚖️ 伦理合规 <a class="header-anchor" href="#⚖️-伦理合规" aria-label="Permalink to &quot;⚖️ 伦理合规&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./ethics-compliance">AI 伦理合规与治理</a></td><td>公平性与偏见检测、EU AI Act 解读、中国监管政策、负责任 AI 设计</td></tr></tbody></table><h3 id="🎯-面试实战" tabindex="-1">🎯 面试实战 <a class="header-anchor" href="#🎯-面试实战" aria-label="Permalink to &quot;🎯 面试实战&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./interview">AI PM 面试高频题 (33+)</a></td><td>33 道面试高频题覆盖 9 大板块，完整实战答案集中收录</td></tr></tbody></table><h3 id="📦-实战与工具" tabindex="-1">📦 实战与工具 <a class="header-anchor" href="#📦-实战与工具" aria-label="Permalink to &quot;📦 实战与工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模块</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="./evaluation">AI 评估体系 ✨</a></td><td>LLM-as-a-Judge、人工评估方法论、评测集构建、A/B 测试统计方法</td></tr><tr><td><a href="./tools-and-workflow">工具链与工作流 ✨</a></td><td>Prompt 管理、实验追踪、数据标注、Agent 搭建、API 调试</td></tr><tr><td><a href="./case-study">实战案例：智能客服 0→1 ✨</a></td><td>端到端全流程：需求验证→MVP 设计→数据准备→模型选型→Prompt 迭代→灰度上线</td></tr><tr><td><a href="./product-teardown">产品拆解与前沿话题 ✨</a></td><td>Perplexity/Cursor/ChatGPT 深度拆解、MCP 协议、AI Coding、AI 浏览器</td></tr></tbody></table><hr><h2 id="面试高频题速览" tabindex="-1">面试高频题速览 <a class="header-anchor" href="#面试高频题速览" aria-label="Permalink to &quot;面试高频题速览&quot;">​</a></h2><h3 id="q1-ai-产品经理和传统产品经理的核心区别是什么" tabindex="-1">Q1: AI 产品经理和传统产品经理的核心区别是什么？ <a class="header-anchor" href="#q1-ai-产品经理和传统产品经理的核心区别是什么" aria-label="Permalink to &quot;Q1: AI 产品经理和传统产品经理的核心区别是什么？&quot;">​</a></h3><details class="details custom-block"><summary>点击查看答案</summary><p><strong>核心差异在四个维度：</strong></p><ol><li><strong>决策逻辑</strong>：传统 PM 依赖确定性规则，AI PM 需要概率思维——你必须接受模型输出&quot;有时是对的有时是错的&quot;，然后设计降级和纠错机制。</li><li><strong>核心驱动</strong>：传统产品是&quot;功能+体验&quot;双轮驱动，AI 产品是&quot;数据-模型-场景&quot;三角驱动。数据质量、模型能力、场景适配三个变量互相耦合。我们在优化客服 Bot 时发现，把 BERT 换成 GPT-4o，不调数据和场景，准确率只提升了 3 个点；但把标注规范改了一版、加了 200 条边界 Case 训练数据，同样的 BERT 提升了 8 个点。</li><li><strong>迭代模式</strong>：传统 PM 按版本发布，AI PM 按数据闭环持续迭代。我们项目的实际工作量分布大概是：数据质量和标注占 40%，模型调优占 30%，功能开发只占 30%。这不是说功能不重要，而是 AI 产品的&quot;功能&quot;质量取决于数据底子。</li><li><strong>技术深度</strong>：传统 PM 能理解 API 文档就够了；AI PM 必须能判断&quot;这个需求用现有模型能不能做、大概做到什么程度&quot;。比如医疗影像产品，你得知道小病灶（&lt;3mm）模型识别不准，才能设计合理的医生复核流程。否则产品方案写了一大堆，技术上根本行不通。</li></ol></details><h3 id="q2-大模型时代-ai-pm-的新定位是什么" tabindex="-1">Q2: 大模型时代 AI PM 的新定位是什么？ <a class="header-anchor" href="#q2-大模型时代-ai-pm-的新定位是什么" aria-label="Permalink to &quot;Q2: 大模型时代 AI PM 的新定位是什么？&quot;">​</a></h3><details class="details custom-block"><summary>点击查看答案</summary><p>大模型时代的核心变化是：<strong>产品经理的价值从&quot;功能设计&quot;转向&quot;能力探索&quot;</strong>。以前你设计一个推荐系统，功能边界是清晰的——用户画像、内容标签、排序策略，每个模块都有明确的功能定义。现在你拿着 GPT-5 这样的大模型，产品形态本身就是变量——你可能今天用它做客服问答，明天发现它能做代码审查，后天又发现它能做合同审核。</p><p>这个变化带来了三个新要求：</p><ol><li><strong>Prompt 即产品</strong>：以前 PRD 是产品规格，现在 Prompt 模板库是产品规格。Notion AI 的团队维护了 2000+ 变体的 Prompt 矩阵，A/B 测试来定最优。你得像个 &quot;Prompt 产品经理&quot;一样思考。</li><li><strong>模型选型能力</strong>：公有云 API vs 行业精调模型 vs 私有化部署，三种方案的选型决定了成本结构和能力上限。百度千帆平台用户调研显示企业对大模型的需求呈&quot;三分天下&quot;格局——35% 用公有云 API、28% 需要精调模型、37% 要求全链路私有化。你得根据场景和预算做出判断。</li><li><strong>合规前置</strong>：欧盟 AI 法案实施后，产品的合规设计不是上线前打个勾，而是从需求阶段就要嵌入。Stability AI 的产品经理 50% 的时间在搞内容过滤机制，这已经成了核心工作之一了。</li></ol></details><h3 id="q3-三个-ai-pm-方向-ai-native-ai-平台-ai-行业-怎么选" tabindex="-1">Q3: 三个 AI PM 方向（AI Native / AI 平台 / AI+行业）怎么选？ <a class="header-anchor" href="#q3-三个-ai-pm-方向-ai-native-ai-平台-ai-行业-怎么选" aria-label="Permalink to &quot;Q3: 三个 AI PM 方向（AI Native / AI 平台 / AI+行业）怎么选？&quot;">​</a></h3><details class="details custom-block"><summary>点击查看答案</summary><p>这三个方向对能力结构的要求完全不同，选错了硬转成本很高：</p><table tabindex="0"><thead><tr><th>方向</th><th>核心能力</th><th>典型公司</th><th>适合背景</th></tr></thead><tbody><tr><td><strong>AI Native</strong></td><td>Prompt 设计、多模态交互、模型能力挖掘</td><td>月之暗面、智谱 AI、MiniMax</td><td>有过 C 端产品经验 + 能快速理解模型能力</td></tr><tr><td><strong>AI 平台</strong></td><td>MLOps 工具链、分布式训练原理、开发者体验</td><td>百度千帆、阿里云 PAI、AWS SageMaker</td><td>有算法或工程背景、懂开发者痛点</td></tr><tr><td><strong>AI+行业</strong></td><td>行业 Know-how + 技术选型判断力 + 变革管理</td><td>京东数科、平安科技、联影智能</td><td>有垂直行业经验、懂业务语言</td></tr></tbody></table><p>我的建议：<strong>技术背景强的优先 AI 平台方向，C 端产品经验丰富的优先 AI Native，有行业经验的优先 AI+。</strong> 零基础入行的，建议从 AI+行业入手——门槛相对低，行业知识是护城河，AI 技术可以在工作中边学边用。</p></details><hr><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>只会写 Prompt 但无法评估模型能力边界——设计出技术上行不通的方案</li><li>对数据闭环理解不到位——以为 AI 产品上线了就完事了，不知道&quot;数据漂移&quot;会悄悄搞垮模型</li><li>混淆三个 AI PM 方向——用 AI 平台 PM 的思路去面试 AI Native 岗位，肯定翻车</li><li>忽视合规——欧盟 AI 法案不是&quot;以后再说&quot;，合规设计现在就是产品设计的必修课</li><li>面试时说不清自己做过什么——AI PM 面试最看实际项目，简历上写&quot;参与大模型项目&quot;但不讲细节很扣分</li></ul></div><h2 id="按你的背景导航" tabindex="-1">按你的背景导航 <a class="header-anchor" href="#按你的背景导航" aria-label="Permalink to &quot;按你的背景导航&quot;">​</a></h2><p>不同背景的读者，建议按以下优先级阅读：</p><table tabindex="0"><thead><tr><th>背景</th><th>优先阅读模块</th><th>说明</th></tr></thead><tbody><tr><td><strong>转型 PM（传统产品经理 → AI PM）</strong></td><td>角色定位 → 技术基础 → 评估体系 → 产品设计 → 工具链 → 案例</td><td>先理解角色差异，再补技术短板，用案例把知识串起来</td></tr><tr><td><strong>算法转 PM</strong></td><td>角色定位 → 产品设计 → 评估体系 → 商业落地 → 案例</td><td>技术不是问题，重点补产品思维、评估方法论和商业感</td></tr><tr><td><strong>零基础/校招</strong></td><td>角色定位 → 技术基础 → 案例 → 产品拆解 → 面试题</td><td>先了解&quot;AI PM 是干什么的&quot;，用案例建立体感，再系统学习</td></tr><tr><td><strong>面试突击</strong></td><td>面试题 → 案例 → 评估体系 → 产品拆解</td><td>以面试题为主线，针对薄弱点补充对应模块</td></tr></tbody></table><hr><h2 id="_8-周自学计划" tabindex="-1">8 周自学计划 <a class="header-anchor" href="#_8-周自学计划" aria-label="Permalink to &quot;8 周自学计划&quot;">​</a></h2><h3 id="第-1-周-认知建立" tabindex="-1">第 1 周：认知建立 <a class="header-anchor" href="#第-1-周-认知建立" aria-label="Permalink to &quot;第 1 周：认知建立&quot;">​</a></h3><ul><li>📖 阅读：<a href="./role-overview">AI PM 角色定位与三大方向</a></li><li>🎯 目标：理解三个方向差异，明确自己的转型路径</li><li>✅ 自检：能说出 AI PM 和传统 PM 的四个本质差异</li></ul><h3 id="第-2-周-技术补课-上" tabindex="-1">第 2 周：技术补课（上） <a class="header-anchor" href="#第-2-周-技术补课-上" aria-label="Permalink to &quot;第 2 周：技术补课（上）&quot;">​</a></h3><ul><li>📖 阅读：<a href="./tech-basics">AI 技术基础</a>（机器学习 + 深度学习部分）</li><li>🛠️ 实操：跑通 Andrew Ng Coursera 课程的前 3 周内容</li><li>✅ 自检：能解释监督学习/无监督学习/强化学习的区别</li></ul><h3 id="第-3-周-技术补课-下" tabindex="-1">第 3 周：技术补课（下） <a class="header-anchor" href="#第-3-周-技术补课-下" aria-label="Permalink to &quot;第 3 周：技术补课（下）&quot;">​</a></h3><ul><li>📖 阅读：<a href="./tech-basics">AI 技术基础</a>（大模型原理 + MLOps 部分）</li><li>🛠️ 实操：用 OpenAI Playground 测试 20+ 个不同 Prompt</li><li>✅ 自检：能说清楚 Token / Embedding / Attention 的心智模型</li></ul><h3 id="第-4-周-ai-产品设计方法论" tabindex="-1">第 4 周：AI 产品设计方法论 <a class="header-anchor" href="#第-4-周-ai-产品设计方法论" aria-label="Permalink to &quot;第 4 周：AI 产品设计方法论&quot;">​</a></h3><ul><li>📖 阅读：<a href="./product-design">AI 产品设计</a> + <a href="./evaluation">评估体系</a></li><li>🛠️ 实操：写一份包含模型需求章节的 AI PRD</li><li>✅ 自检：能独立完成 AI 适用性矩阵评估一个需求</li></ul><h3 id="第-5-周-数据与-prompt" tabindex="-1">第 5 周：数据与 Prompt <a class="header-anchor" href="#第-5-周-数据与-prompt" aria-label="Permalink to &quot;第 5 周：数据与 Prompt&quot;">​</a></h3><ul><li>📖 阅读：<a href="./data-model-management">数据与模型管理</a> + <a href="./prompt-engineering">Prompt 工程</a></li><li>🛠️ 实操：设计一份标注规范 + 写一个完整的 System Prompt</li><li>✅ 自检：能说出 Prompt 五要素，并能举一个自己设计的 Prompt 例子</li></ul><h3 id="第-6-周-大模型与工具链" tabindex="-1">第 6 周：大模型与工具链 <a class="header-anchor" href="#第-6-周-大模型与工具链" aria-label="Permalink to &quot;第 6 周：大模型与工具链&quot;">​</a></h3><ul><li>📖 阅读：<a href="./large-model">大模型与 Agent</a> + <a href="./tools-and-workflow">工具链与工作流</a></li><li>🛠️ 实操：用 Dify 搭一个带知识库的 QA Bot</li><li>✅ 自检：能解释 RAG 和 Fine-tuning 的适用场景差异</li></ul><h3 id="第-7-周-产品思维与实战" tabindex="-1">第 7 周：产品思维与实战 <a class="header-anchor" href="#第-7-周-产品思维与实战" aria-label="Permalink to &quot;第 7 周：产品思维与实战&quot;">​</a></h3><ul><li>📖 阅读：<a href="./case-study">实战案例</a> + <a href="./product-teardown">产品拆解与前沿</a></li><li>🛠️ 实操：拆解 3 个 AI 产品（Perplexity、Cursor、ChatGPT），写出你的产品分析</li><li>✅ 自检：能对一个 AI 产品做深度拆解，说出它的产品逻辑和可改进之处</li></ul><h3 id="第-8-周-面试冲刺" tabindex="-1">第 8 周：面试冲刺 <a class="header-anchor" href="#第-8-周-面试冲刺" aria-label="Permalink to &quot;第 8 周：面试冲刺&quot;">​</a></h3><ul><li>📖 阅读：<a href="./interview">面试高频题 (33+)</a> + 回顾所有笔记</li><li>🛠️ 实操：做 3 次模拟面试（找朋友或录音自测） + 准备 3 个项目 STAR</li><li>✅ 自检：33 道题中有 25 道以上能流畅回答</li></ul><hr><h2 id="ai-pm-能力自评表" tabindex="-1">AI PM 能力自评表 <a class="header-anchor" href="#ai-pm-能力自评表" aria-label="Permalink to &quot;AI PM 能力自评表&quot;">​</a></h2><p>对照这个评估表，定位自己的能力短板：</p><table tabindex="0"><thead><tr><th>能力维度</th><th>1 分（新手）</th><th>2 分（入门）</th><th>3 分（熟练）</th><th>4 分（精通）</th><th>5 分（专家）</th></tr></thead><tbody><tr><td><strong>技术理解力</strong></td><td>不懂 ML 基本概念</td><td>能说清 ML/DL 基本原理</td><td>能判断需求的技术可行性</td><td>能独立做模型选型决策</td><td>能与算法团队深度对话</td></tr><tr><td><strong>产品设计力</strong></td><td>只懂功能设计</td><td>理解概率化 UX 的概念</td><td>能设计 AI 产品的降级策略</td><td>能独立设计完整的 AI 产品方案</td><td>能定义行业级的 AI 产品范式</td></tr><tr><td><strong>数据管理力</strong></td><td>从未设计过标注规范</td><td>理解数据标注的基本流程</td><td>能设计标注规范并做质量控制</td><td>能搭建完整的数据闭环体系</td><td>能构建数据驱动的产品飞轮</td></tr><tr><td><strong>Prompt 能力</strong></td><td>只会用默认 Prompt</td><td>能写基本的结构化 Prompt</td><td>能迭代优化 Prompt 并 A/B 测试</td><td>能设计复杂的 Few-shot 策略</td><td>能定义团队的 Prompt 工程规范</td></tr><tr><td><strong>商业思维</strong></td><td>只关注功能</td><td>能算清 API 成本</td><td>能设计定价策略</td><td>能做 ROI 测算说服管理层</td><td>能从 0 到 1 定义 AI 商业模式</td></tr><tr><td><strong>伦理合规</strong></td><td>不知道有合规要求</td><td>了解 EU AI Act 基本框架</td><td>能在设计阶段考虑公平性</td><td>能独立做 Bias 审查和修正</td><td>能定义产品的负责任 AI 标准</td></tr></tbody></table><p><strong>评分方法</strong>：</p><ul><li><strong>≥ 24 分</strong>：你已经是一名称职的 AI PM，继续深化你的核心方向</li><li><strong>18-23 分</strong>：基础扎实，需要有针对性的提升短板维度</li><li><strong>12-17 分</strong>：处于转型期，重点补技术基础和产品设计</li><li><strong>&lt; 12 分</strong>：从&quot;角色定位&quot;和&quot;技术基础&quot;两个模块开始系统学习</li></ul><details class="details custom-block"><summary>推荐资源</summary><ul><li><strong>入门书籍</strong>：《人工智能产品经理》- 苏杰 / 《AI 产品经理》实践指南</li><li><strong>技术课程</strong>：Andrew Ng 机器学习 Coursera / Fast.ai 实战 / DeepLearning.AI LangChain 系列</li><li><strong>行业报告</strong>：Gartner AI Hype Cycle / 各券商 AI 行业研究报告</li><li><strong>社区</strong>：即刻 AI 产品经理圈子 / 知乎 &quot;AI 产品&quot;话题</li><li><strong>工具</strong>：OpenAI Playground / Dify / LangSmith / LabelStudio</li></ul></details>',59))])}const p=o(E,[["render",u]]);export{P as __pageData,p as default};
